class UnionFind:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]  # path compression
            x = self.parent[x]
        return x

    def union(self, x: int, y: int):
        px, py = self.find(x), self.find(y)
        if px == py: return
        if self.rank[px] < self.rank[py]: px, py = py, px
        self.parent[py] = px
        if self.rank[px] == self.rank[py]: self.rank[px] += 1

def cluster_and_select(docs: list[dict], candidate_pairs: list[tuple[int,int]]) -> list[dict]:
    """Given near-duplicate pairs, keep the longest document per cluster."""
    uf = UnionFind(len(docs))
    for a, b in candidate_pairs:
        uf.union(a, b)
    # Group docs by cluster root
    clusters: dict[int, list[int]] = {}
    for i in range(len(docs)):
        root = uf.find(i)
        clusters.setdefault(root, []).append(i)
    # From each cluster, keep the document with the most words
    kept = []
    for indices in clusters.values():
        best = max(indices, key=lambda i: len(docs[i]["text"].split()))
        kept.append(docs[best])
    return kept
